import{_ as a,a as e,b as d,c as i,d as p,e as n}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as s,o as r,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"IP 定位與使用者管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/ip-geolocation-and-user-management.md","filePath":"zh-TW/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),h={name:"zh-TW/Other/ip-geolocation-and-user-management.md"};function c(b,t,P,u,m,g){return r(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="ip-定位與使用者管理" tabindex="-1">IP 定位與使用者管理 <a class="header-anchor" href="#ip-定位與使用者管理" aria-label="Permalink to &quot;IP 定位與使用者管理&quot;">​</a></h1><p>IP 定位會把上傳者、登入裝置等紀錄裡的 IP 顯示成大概地理位置。</p><p>啟用後，後台可以更直觀看到訪問來源、上傳來源，也可以在使用者管理裡針對異常 IP 單獨禁止或恢復上傳。</p><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定 -&gt; IP 定位</span></span></code></pre></div><p><img src="'+a+`" alt="IP 定位" loading="lazy"></p><h2 id="可以設定什麼" tabindex="-1">可以設定什麼 <a class="header-anchor" href="#可以設定什麼" aria-label="Permalink to &quot;可以設定什麼&quot;">​</a></h2><p>新版 IP 定位支援多個來源，不再只依賴單一地圖服務。</p><table tabindex="0"><thead><tr><th>設定項</th><th>作用</th></tr></thead><tbody><tr><td>IP 解析語言</td><td>選擇地址顯示語言，例如 English、繁體中文、日本語、Français</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind 帳號 ID，用於 MaxMind GeoLite Web Service</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key</td></tr><tr><td>騰訊地圖 Key</td><td>騰訊位置服務 Key，適合中文地址和中國大陸 IP</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi Key，支援多語 IP 地址解析</td></tr></tbody></table><p>這些設定可以依需求填，不需要全部都填。</p><p>如果什麼 Key 都不填，系統也會嘗試使用內建免費來源解析 IP，只是穩定性、語言支援和精準度可能不如自己設定的服務。</p><h2 id="推薦怎麼選" tabindex="-1">推薦怎麼選 <a class="header-anchor" href="#推薦怎麼選" aria-label="Permalink to &quot;推薦怎麼選&quot;">​</a></h2><p>如果你主要看中文地址：</p><ol><li>IP 解析語言選「繁體中文」或需要的中文語系。</li><li>有需要時設定騰訊地圖 Key。</li><li>也可以再設定 MaxMind 或 ipapi 作為補充。</li></ol><p>如果你主要看英文或多語地址：</p><ol><li>IP 解析語言選需要的語言。</li><li>設定 MaxMind Account ID 和 License Key。</li><li>需要更好的多語結果時，再設定 ipapi Key。</li></ol><h2 id="maxmind-怎麼設定" tabindex="-1">MaxMind 怎麼設定 <a class="header-anchor" href="#maxmind-怎麼設定" aria-label="Permalink to &quot;MaxMind 怎麼設定&quot;">​</a></h2><p>MaxMind 需要填兩項：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>在 MaxMind 後台可以看到 Account ID，並在 License Keys 頁面產生 License Key。</p><p><img src="`+e+'" alt="MaxMind Key 設定" loading="lazy"></p><p>產生後，把 Account ID 和 License Key 分別填回 ImgBed 後台儲存。</p><p>MaxMind 免費方案適合日常使用，但有呼叫次數限制。如果超過額度，系統會繼續嘗試其他可用來源。</p><h2 id="ipapi-怎麼設定" tabindex="-1">ipapi 怎麼設定 <a class="header-anchor" href="#ipapi-怎麼設定" aria-label="Permalink to &quot;ipapi 怎麼設定&quot;">​</a></h2><p>ipapi 使用 APILayer 的 API Key。</p><p>進入 ipapi 控制台後，複製頁面上的 API Key。</p><p><img src="'+d+'" alt="ipapi 設定" loading="lazy"></p><p>然後填入 ImgBed 後台的 <code>ipapi Key</code> 並儲存。</p><p>ipapi 支援多語 IP 地址解析，適合想讓後台地址依指定語言顯示的情境。免費方案也有次數限制，用完後系統會繼續嘗試其他可用來源。</p><h2 id="騰訊地圖-key-怎麼設定" tabindex="-1">騰訊地圖 Key 怎麼設定 <a class="header-anchor" href="#騰訊地圖-key-怎麼設定" aria-label="Permalink to &quot;騰訊地圖 Key 怎麼設定&quot;">​</a></h2><p>騰訊地圖 Key 適合中文地址，尤其是中國大陸 IP。</p><p>在騰訊位置服務控制台建立 Key 時，建議啟用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>建立完成後，把 Key 填到「騰訊地圖 Key」裡儲存。</p><h2 id="使用者管理看什麼" tabindex="-1">使用者管理看什麼 <a class="header-anchor" href="#使用者管理看什麼" aria-label="Permalink to &quot;使用者管理看什麼&quot;">​</a></h2><p>入口在後台頂部的使用者管理。</p><p><img src="'+i+'" alt="使用者管理顯示" loading="lazy"></p><p>使用者管理主要看每個 IP 的上傳狀況：</p><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>IP 來源</td><td>上傳者來源 IP</td></tr><tr><td>地址</td><td>IP 定位解析出的大概位置</td></tr><tr><td>上傳總量</td><td>這個 IP 上傳檔案占用的總大小</td></tr><tr><td>上傳次數</td><td>這個 IP 上傳過幾次</td></tr><tr><td>允許上傳</td><td>開啟代表允許，關閉代表禁止上傳</td></tr></tbody></table><p>點左側展開箭頭，可以查看這個 IP 上傳過的檔案列表。</p><p>檔案列表裡可以看到檔名、預覽、大小、審查結果、檔案狀態和上傳時間。遇到異常上傳時，可以先展開看具體檔案，再決定是否禁止這個 IP 繼續上傳。</p><h2 id="搜尋、排序和進階篩選" tabindex="-1">搜尋、排序和進階篩選 <a class="header-anchor" href="#搜尋、排序和進階篩選" aria-label="Permalink to &quot;搜尋、排序和進階篩選&quot;">​</a></h2><p>使用者管理頂部可以搜尋 IP 來源或地址。</p><p>排序可依時間、上傳次數、上傳總量切換，方便先看最近上傳、上傳次數最多，或占用空間最大的 IP。</p><p>需要更精準排查時，可以打開進階篩選。</p><p><img src="'+p+'" alt="使用者管理進階篩選" loading="lazy"></p><p>進階篩選支援：</p><table tabindex="0"><thead><tr><th>篩選項</th><th>用法</th></tr></thead><tbody><tr><td>時間範圍</td><td>只看某段時間內上傳過檔案的 IP</td></tr><tr><td>存取狀態</td><td>依正常、封鎖等狀態篩選</td></tr><tr><td>黑白名單</td><td>依白名單、黑名單、未設定篩選</td></tr><tr><td>檔案類型</td><td>只看上傳過圖片、影片、音訊、文件、程式碼或其他類型的 IP</td></tr><tr><td>檔案大小</td><td>依上傳檔案大小範圍篩選</td></tr><tr><td>年齡分級</td><td>依未設定、全年齡、R12+、R16+、R18 等分級篩選</td></tr><tr><td>檔案狀態</td><td>依檔案目前狀態篩選，方便排查異常檔案</td></tr></tbody></table><p>篩選完點「套用篩選」即可，需要恢復全部資料時點「重設」。</p><h2 id="手機版顯示" tabindex="-1">手機版顯示 <a class="header-anchor" href="#手機版顯示" aria-label="Permalink to &quot;手機版顯示&quot;">​</a></h2><p>手機版會把使用者管理改成卡片顯示。</p><p><img src="'+n+`" alt="手機版使用者管理" loading="lazy"></p><p>每張卡片會顯示 IP、地址、上傳總量、上傳次數和允許上傳開關，不需要橫向拖表格也能操作。</p><h2 id="地址不準怎麼辦" tabindex="-1">地址不準怎麼辦 <a class="header-anchor" href="#地址不準怎麼辦" aria-label="Permalink to &quot;地址不準怎麼辦&quot;">​</a></h2><p>IP 定位顯示的是大概位置，不是精準門牌地址。</p><p>如果使用者使用代理、機房、雲端伺服器或跨境網路，顯示位置可能和真實位置不同。</p><p>這個功能比較適合判斷大致來源、發現異常上傳、輔助封鎖，不建議當成精確定位工具。</p><h2 id="常見情況" tabindex="-1">常見情況 <a class="header-anchor" href="#常見情況" aria-label="Permalink to &quot;常見情況&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情況</th><th>說明</th></tr></thead><tbody><tr><td>地址顯示空白</td><td>可能還沒解析成功，或目前 IP 來源暫時不可用</td></tr><tr><td>地址語言不對</td><td>檢查 IP 解析語言，並確認已設定支援該語言的來源</td></tr><tr><td>地址顯示成機房</td><td>很多代理、雲端伺服器、爬蟲工具都會顯示成機房或 ISP 地址</td></tr><tr><td>上傳次數很高</td><td>可以重點檢查這個 IP，必要時關閉允許上傳</td></tr><tr><td>上傳總量很大</td><td>可排序或篩選後展開查看具體檔案</td></tr><tr><td>禁止後想恢復</td><td>把「允許上傳」重新打開即可</td></tr></tbody></table><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打開其他設定裡的 IP 定位</span></span>
<span class="line"><span>-&gt; 選 IP 解析語言</span></span>
<span class="line"><span>-&gt; 依需求填 MaxMind、騰訊地圖或 ipapi</span></span>
<span class="line"><span>-&gt; 儲存</span></span>
<span class="line"><span>-&gt; 打開使用者管理查看 IP 來源、地址、上傳總量和次數</span></span>
<span class="line"><span>-&gt; 用搜尋、排序或進階篩選排查異常 IP</span></span>
<span class="line"><span>-&gt; 依需要允許或禁止上傳</span></span></code></pre></div>`,61)])])}const _=s(h,[["render",c]]);export{y as __pageData,_ as default};
